#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long A, B, N;
        scanf("%lld %lld %lld", &A, &B, &N);
        for (int i = 0; i < N; i++) {
            if (i % 2 == 0) A *= 2;
            else B *= 2;
        }
        long long max = (A > B) ? A : B;
        long long min = (A < B) ? A : B;
        printf("%lld\n", max / min);
    }
    return 0;
}

