code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long A = sc.nextLong();
            long B = sc.nextLong();
            long N = sc.nextLong();
            for (int i = 0; i < N; i++) {
                if (i % 2 == 0) A *= 2;
                else B *= 2;
            }
            long max = Math.max(A, B);
            long min = Math.min(A, B);
            System.out.println(max / min);
        }
    }
}

